fn read()->Vec<i32>{
    let mut line=String::new();
    std::io::stdin().read_line(&mut line).unwrap();
    line.split_whitespace().map(|x|x.parse::<i32>().unwrap()).collect()
}
use std::i32;
fn main(){
    let vec=read();
    let stairs=i32::abs(vec[0]-vec[1])*vec[3];
    let lift=i32::abs(vec[0]-vec[1])*vec[4]+3*vec[5]+i32::abs(vec[0]-vec[2])*vec[4];
    if lift<=stairs{
        println!("YES");
    }
    else{
        println!("NO");
    }
}
